// ===============================
// 📌 CV PARSER — POST-PROCESS NODE
// Extracts all fields from Claude output
// ===============================

const input = $input.first().json;

// =====================
// STEP 1: Get raw text from Claude response
// =====================
const rawText =
  input?.content?.[0]?.text ||   // HTTP Request node format
  input?.text ||                  // direct text field
  input?.message?.content?.[0]?.text ||
  "";

if (!rawText) {
  throw new Error("No Claude response found. Check previous node output.");
}

// =====================
// STEP 2: Clean & parse JSON
// =====================
const jsonString = rawText
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/```\s*$/i, "")
  .trim();

let parsed;
try {
  parsed = JSON.parse(jsonString);
} catch (e) {
  const match = jsonString.match(/\{[\s\S]+\}/);
  if (match) {
    try {
      parsed = JSON.parse(match[0]);
    } catch (e2) {
      throw new Error("Failed to parse JSON. Raw preview: " + rawText.substring(0, 300));
    }
  } else {
    throw new Error("No JSON object found in response. Raw preview: " + rawText.substring(0, 300));
  }
}

// =====================
// STEP 3: Normalize all fields
// =====================

// Arrays
parsed.skills          = Array.isArray(parsed.skills)          ? parsed.skills          : [];
parsed.internships     = Array.isArray(parsed.internships)     ? parsed.internships     : [];
parsed.projects        = Array.isArray(parsed.projects)        ? parsed.projects        : [];
parsed.education       = Array.isArray(parsed.education)       ? parsed.education       : [];
parsed.certifications  = Array.isArray(parsed.certifications)  ? parsed.certifications  : [];
parsed.languages       = Array.isArray(parsed.languages)       ? parsed.languages       : [];

// Strings
parsed.name             = parsed.name             || "";
parsed.email            = parsed.email            || "";
parsed.phone            = parsed.phone            || "";
parsed.track            = parsed.track            || "";
parsed.experience_level = parsed.experience_level || "Fresher";
parsed.summary          = parsed.summary          || "";

// Numbers
parsed.years_experience  = parsed.years_experience  ?? 0;
parsed.confidence_score  = parsed.confidence_score  ?? 0;

// Fix URLs — add https:// if missing
if (parsed.linkedin && !parsed.linkedin.startsWith("http")) {
  parsed.linkedin = "https://" + parsed.linkedin;
}
if (parsed.github && !parsed.github.startsWith("http")) {
  parsed.github = "https://" + parsed.github;
}

// =====================
// STEP 4: Add metadata
// =====================
parsed.parsed_at   = new Date().toISOString();
parsed.skill_count = parsed.skills.length;

// =====================
// STEP 5: Return flat clean object
// =====================
return {
  // ── Identity ──────────────────────
  name:              parsed.name,
  email:             parsed.email,
  phone:             parsed.phone,
  linkedin:          parsed.linkedin,
  github:            parsed.github,

  // ── Career ────────────────────────
  track:             parsed.track,
  years_experience:  parsed.years_experience,
  experience_level:  parsed.experience_level,
  summary:           parsed.summary,

  // ── Skills ────────────────────────
  skills:            parsed.skills,
  skill_count:       parsed.skill_count,

  // ── Experience ────────────────────
  internships:       parsed.internships,
  projects:          parsed.projects,

  // ── Education ─────────────────────
  education:         parsed.education,
  certifications:    parsed.certifications,
  languages:         parsed.languages,

  // ── Meta ──────────────────────────
  confidence_score:  parsed.confidence_score,
  parsed_at:         parsed.parsed_at,
};
